SELECT a.*, b.*
FROM {TABLE_A} a
INNER JOIN {TABLE_B} b ON a.id = b.{FK};

SELECT a.*, b.*
FROM {TABLE_A} a
LEFT JOIN {TABLE_B} b ON a.id = b.{FK};

SELECT a.*, b.*
FROM {TABLE_A} a
RIGHT JOIN {TABLE_B} b ON a.id = b.{FK};

SELECT a.{COL}, b.{COL}
FROM {TABLE} a
JOIN {TABLE} b ON a.{FK} = b.id;

SELECT {COL}, COUNT(*) AS cnt
FROM {TABLE}
GROUP BY {COL}
ORDER BY cnt DESC;

SELECT {COL}, COUNT(*) AS cnt
FROM {TABLE}
GROUP BY {COL}
HAVING COUNT(*) > {N};

WITH cte AS (
  SELECT * FROM {TABLE} WHERE {CONDITION}
)
SELECT * FROM cte;

SELECT * FROM {TABLE}
WHERE id IN (
  SELECT id FROM {OTHER_TABLE} WHERE {CONDITION}
);

SELECT
  *,
  ROW_NUMBER() OVER (
    PARTITION BY {COL}
    ORDER BY {COL2} DESC
  ) AS rn
FROM {TABLE};

CREATE TABLE IF NOT EXISTS {TABLE} (
  id SERIAL PRIMARY KEY,
  {COL} {TYPE} NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

BEGIN;
{SQL_OPERATIONS};
COMMIT;
-- On error: ROLLBACK;
